INSERT INTO public.skill_chunks VALUES ('d6ksthr24teo5tb24teg', '84ba61db5206ca8dcbb3', 0, '
# Business Operations Management

Comprehensive skill for managing business operations across professional services (dental, legal, medical, consulting).

## When to Use

