INSERT INTO public.skill_chunks VALUES ('d6kscir24tenqfr24v2g', 'd6ksbjb24tenp4324sr0', 5, 'e = ''https://searx.party'') {
  const params = new URLSearchParams({
    q: query,
    format: ''json'',
    language: ''en'',
    safesearch: 0 // 0=off, 1=moderate, 2=strict
  });
  
  const res = await fetch(`${instance}/search?${params}`);
  const data = await res.json();
  
  return data.results.map(r => ({
    title: r.title,
    url: r.url,
    content: r.content,
    engine: r.engine // which search engine provided this result
  }));
}

