**Steps:**
```python
from ace_step import ACEStep

model = ACEStep.from_pretrained("ACE-Step/ACE-Step-v1-3.5B")

# Define mask (what to change)
mask = {
    "start_time": 30,  # seconds
    "end_time": 45,
    "operation": "repaint"
}

# Apply repainting
edited_aud', '2026-03-05 13:47:29.92707-05', NULL);
INSERT INTO public.skill_chunks VALUES ('d6kscir24tenqfr24vpg', 'd6ksbjb24tenp6j24teg', 6, ', table) => {
    const category = $(table).find(''th'').text().trim();
    specs[category] = {};
    
    $(table).find(''tr'').each((j, row) => {
      const key = $(row).find(''td.ttl'').text().trim();
      const value = $(row).find(''td.nfo'').text().trim();
      if (key && value) {
        specs[category][key] = value;
      }
    });
  });
  
  return specs;
}

