INSERT INTO public.skill_chunks VALUES ('d6kscir24tenqfr25040', 'd6ksbn324tenper24tg0', 5, 'se and pick best match (simple majority on country+city)
  const votes = {};
  for(const r of Object.values(results)){
    if(!r || r.error) continue;
    const country = r.country || r.country_name || r.countryCode || null;
    const city = r.city || r.city_name || null;
    const key = `${country||''?''}/${city||''?''}`;
    votes[key] = (votes[key]||0)+1;
  }
  const best = Object.entries(votes).sort((a,b)=>b[1]-a[1])[0];
  return {best: best?best[0]:null,score: best?best[1]:0,results};
}

