  // Split CSV line (basic implementation)
  const splitCSVLine = (line) => {
    const result = [];
    let current = '''';
    let inQuotes = false;
    
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      
      if (char === ''"'') {
        inQuotes = !inQuotes;
        current += char;
      } else if (char === '','' && !inQuotes) {
        result.push(parseCSVValue(current));
        current = '''';
      } else {
        current += char;
      }
    }
